Here's a C++ program that reads a text file line by line and counts the number of occurrences of a specific word in the file:

```cpp
#include <iostream>
#include <fstream>
#include <string>

int main() {
    std::string filename, word;
    int count = 0;

    std::cout << "Enter the filename: ";
    std::cin >> filename;

    std::cout << "Enter the word to count: ";
    std::cin >> word;

    std::ifstream file(filename);

    if (file.is_open()) {
        std::string line;
        while (std::getline(file, line)) {
            size_t pos = 0;
            while ((pos = line.find(word, pos)) != std::string::npos) {
                count++;
                pos += word.length();
            }
        }
        file.close();
        std::cout << "The word \"" << word << "\" occurs " << count << " times in the file." << std::endl;
    } else {
        std::cout << "Unable to open the file." << std::endl;
    }

    return 0;
}
```

